import{_ as o,o as a,c as t,ae as r}from"./chunks/framework.BGHOrOyn.js";const h=JSON.parse('{"title":"Useful Mapbox Geocoding API Info","description":"https://docs.mapbox.com/help/getting-started/geocoding/#result-prioritization-in-reverse-geocoding","frontmatter":{"description":"https://docs.mapbox.com/help/getting-started/geocoding/#result-prioritization-in-reverse-geocoding"},"headers":[],"relativePath":"gis/geocoding/mapbox-geocoding-api/useful-mapbox-geocoding-api-info.md","filePath":"gis/geocoding/mapbox-geocoding-api/useful-mapbox-geocoding-api-info.md"}'),i={name:"gis/geocoding/mapbox-geocoding-api/useful-mapbox-geocoding-api-info.md"};function s(n,e,c,d,l,p){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="useful-mapbox-geocoding-api-info" tabindex="-1">Useful Mapbox Geocoding API Info <a class="header-anchor" href="#useful-mapbox-geocoding-api-info" aria-label="Permalink to &quot;Useful Mapbox Geocoding API Info&quot;">​</a></h1><p>The <a href="https://docs.mapbox.com/api/search/#geocoding" target="_blank" rel="noreferrer">Mapbox Geocoding API</a> performs two main tasks: <em>forward geocoding</em> and <em>reverse geocoding</em>. Forward geocoding converts text into geographic coordinates, for example, turning <code>2 Lincoln Memorial Circle NW</code> into <code>-77.050,38.889</code>. Reverse geocoding converts geographic coordinates into a text description, for example, turning <code>-77.050,38.889</code> into <code>2 Lincoln Memorial Circle NW</code>.</p><p>All geocoding requests require you to submit a <em>query</em>, or what you&#39;re trying to find. When you make a query, you get a <em>response</em>, a JSON-formatted document of the most relevant results from your query. This guide provides an overview of how the Geocoding API works, how to use it, how to provide feedback, and links to relevant documentation to get you started.</p><h2 id="geocoding-demo" tabindex="-1">Geocoding demo <a href="#geocoding-demo" id="geocoding-demo"></a> <a class="header-anchor" href="#geocoding-demo" aria-label="Permalink to &quot;Geocoding demo &lt;a href=&quot;#geocoding-demo&quot; id=&quot;geocoding-demo&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>In the demo below, you can type in a location to make a Geocoding API query view then view the response as raw JSON:</p><p>The demo uses the <a href="https://github.com/mapbox/mapbox-gl-geocoder" target="_blank" rel="noreferrer">Mapbox GL geocoder plugin</a> to add forward geocoding to a web app built with Mapbox GL JS.</p><p>Geocoding results are returned in <a href="https://github.com/mapbox/carmen/blob/master/carmen-geojson.md" target="_blank" rel="noreferrer">Carmen GeoJSON</a> format and contain both descriptive location information and geographic information.</p><p>You can use the geographic information returned in the JSON response to show your query on a map, like in this example, or do additional spatial analysis.</p><h3 id="how-geocoding-works" tabindex="-1">How geocoding works <a href="#how-geocoding-works" id="how-geocoding-works"></a> <a class="header-anchor" href="#how-geocoding-works" aria-label="Permalink to &quot;How geocoding works &lt;a href=&quot;#how-geocoding-works&quot; id=&quot;how-geocoding-works&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>The <a href="https://docs.mapbox.com/api/search/#geocoding" target="_blank" rel="noreferrer">Mapbox Geocoding API</a> has two distinct parts: the <strong>source data</strong> we use to define locations and the <strong>tools</strong> we use to search for and return those locations.</p><h4 id="source-data" tabindex="-1">Source data <a href="#source-data" id="source-data"></a> <a class="header-anchor" href="#source-data" aria-label="Permalink to &quot;Source data &lt;a href=&quot;#source-data&quot; id=&quot;source-data&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The Mapbox Geocoding API contains <a href="https://www.mapbox.com/about/maps/#data-sources" target="_blank" rel="noreferrer">data sources</a> from governments, open data projects, and private companies. In some cases, results from the Geocoding API may differ from <a href="https://docs.mapbox.com/data/tilesets/reference/mapbox-streets-v8/" target="_blank" rel="noreferrer">Mapbox Streets</a> or OpenStreetMap data.</p><p>The Mapbox Geocoding API source data contains the following types of geographic information, ordered from the most granular to the largest:</p><ul><li><strong>Points of interest (POI):</strong> A named place including commercial businesses, public buildings, monuments, and parks, among other features.</li><li><strong>Address:</strong> A specific mailing address, including the address number if applicable.</li><li><strong>Neighborhood:</strong> A colloquial name for a smaller area within a place. Neighborhoods do not necessarily have specific, legally defined boundaries. Only present in some countries.</li><li><strong>Locality:</strong> An administrative unit that is smaller than a place. Only present in some countries.</li><li><strong>Postcode:</strong> A geographic area of the address component used for sorting mail.</li><li><strong>Place:</strong> Cities, towns, and villages. Note that some large cities (such as Tokyo and Istanbul) may be categorized as regions rather than places.</li><li><strong>District:</strong> An administrative unit that is larger than a place but smaller than a region. Only present in some countries.</li><li><strong>Region:</strong> States, provinces, and prefectures. This is typically the largest sub-national administrative unit of a country. Note that some large cities (such as Tokyo and Istanbul) may be categorized as regions rather than places.</li><li><strong>Country:</strong> Generally recognized countries or, in some cases like Hong Kong, an area of quasi-national administrative status that has been given a designated country code under ISO 3166-1.</li></ul><p>This hierarchy of feature types is also used to determine what will be returned as the encompassing parent features in a Geocoding API response object&#39;s <a href="https://docs.mapbox.com/api/search/#geocoding-response-object" target="_blank" rel="noreferrer"><code>context</code> property</a>. For example, if the returned feature is a <code>place</code> (like Detroit), then the encompassing parent features in the <code>context</code> property will be the <code>region</code> (the state of Michigan) and the <code>country</code> (United States).</p><h4 id="tools" tabindex="-1">Tools <a href="#tools" id="tools"></a> <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools &lt;a href=&quot;#tools&quot; id=&quot;tools&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The Mapbox Geocoding API uses <a href="https://github.com/mapbox/carmen" target="_blank" rel="noreferrer">Carmen</a>, an open source project for Mapnik vector tile-based geocoding. For more on Carmen, see <a href="https://github.com/mapbox/carmen#how-does-carmen-work" target="_blank" rel="noreferrer">How does Carmen work?</a>.</p><h4 id="customizing-your-queries" tabindex="-1">Customizing your queries <a href="#customizing-your-queries" id="customizing-your-queries"></a> <a class="header-anchor" href="#customizing-your-queries" aria-label="Permalink to &quot;Customizing your queries &lt;a href=&quot;#customizing-your-queries&quot; id=&quot;customizing-your-queries&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The Mapbox Geocoding API accepts many optional parameters. You can use these optional parameters to customize your queries so that the most relevant results are returned. These parameters can be specified using URL query parameters, or they can be specified as options with one of our client-side libraries or plugins. These parameters allow you to view results as you type, filter results by geographic feature type, and limit or bias results to a specified area. For example, to limit your search results to addresses in the Washington DC Metro area, you could set the <code>type</code> parameter to <code>address</code> and the <code>bbox</code> parameter to <code>-77.08,38.90,-76.99,38.95</code>. With those parameters set, your query for <code>Constitution Ave</code> will only return street addresses in the DC Metro area, and will not include features you&#39;re not interested in (like <code>Constitution Ave, El Paso, Texas 79908, United States</code>).</p><p>Read the <a href="https://docs.mapbox.com/api/search/#geocoding" target="_blank" rel="noreferrer">Geocoding API documentation</a> for more information on available features.</p><h4 id="language-support" tabindex="-1">Language support <a href="#language-support" id="language-support"></a> <a class="header-anchor" href="#language-support" aria-label="Permalink to &quot;Language support &lt;a href=&quot;#language-support&quot; id=&quot;language-support&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>The Mapbox Geocoding API accepts a <code>language</code> query parameter, which allows you to specify the language in which you would like to search. One or more languages can be specified using <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank" rel="noreferrer">ISO 639-1 codes</a>. Translation availability varies by language and region, and you can expect more consistent results for areas where the specified language is most widely used. Language support has three different levels:</p><ul><li><strong>Global coverage.</strong> These languages are almost always present for <code>country</code>, <code>region</code>, and prominent <code>place</code> features.</li><li><strong>Local coverage.</strong> These languages may lack global coverage, but they are almost always present for <code>country</code>, <code>region</code>, and prominent <code>place</code> features where they are widely used.</li><li><strong>Limited coverage.</strong> These languages are sometimes present, but coverage tends to be inconsistent or geographically constrained.</li></ul><p>For a current list of the languages covered at each level, see the <a href="https://docs.mapbox.com/api/search/#language-coverage" target="_blank" rel="noreferrer">Geocoding API documentation</a>.</p><h4 id="search-result-prioritization" tabindex="-1">Search result prioritization <a href="#search-result-prioritization" id="search-result-prioritization"></a> <a class="header-anchor" href="#search-result-prioritization" aria-label="Permalink to &quot;Search result prioritization &lt;a href=&quot;#search-result-prioritization&quot; id=&quot;search-result-prioritization&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Results from geocoding queries are prioritized differently depending on whether the request was a <em>forward geocode</em> or a <em>reverse geocode</em>.</p><p><strong>Result prioritization in forward geocoding</strong></p><p>When a forward geocoding query (human-readable text like “San Francisco”) is submitted to the Mapbox Geocoding API, the geocoder uses Carmen, a text search engine, to search our spatial indexes for features that match the user’s query. (For a more detailed description of how the Carmen text search engine works, read the <a href="https://github.com/mapbox/carmen/blob/master/docs/how-carmen-works.md" target="_blank" rel="noreferrer">Carmen documentation</a>.) The geocoder applies filters on the backend to sort the results that match, or partially match, the searched text. These filters are <em>textual relevance</em> and <em>prominence score</em>.</p><p><strong>Textual relevance</strong></p><p>When the geocoder sorts and prioritizes results, the first filter that is applied is <code>relevance</code>. <code>relevance</code> is a value that indicates how well a feature in our dataset matches the query. This property is surfaced in the Geocoding API response, and is a numerical score from <code>0</code> (the result does not match the queried text at all) to <code>1</code> (the result matches the queried text most completely). You can use the <code>relevance</code> property to remove results that don&#39;t fully match the query.</p><p>In this example query for the address “515 15th St NW, Washington, DC 20004”, the expected result is first in the response with a <code>relevance</code> of <code>0.875</code>. Other results in other cities, since they don’t match the search text as closely, have a <code>relevance</code> score of <code>0.2</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.mapbox.com/geocoding/v5/mapbox.places/515%2015th%20St%20NW%2C%20Washington%2C%20DC%2020004.json?types=address&amp;access_token=YOUR_MAPBOX_ACCESS_TOKEN</span></span></code></pre></div><p><strong>Prominence score</strong></p><p>In the case that multiple features have the same <code>relevance</code> score, a second filter called <code>score</code> is applied. This is based on the popularity or prominence of a feature. For example, a search for “Paris” will equally match “Paris, France” and “Paris, Texas” — they’ll have the same <code>relevance</code> score. The <code>score</code> filter helps break this tie on the backend, and surfaces “Paris, France” first since it is a more popular feature:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">api.mapbox.com</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">geocoding</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">v5</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mapbox.places</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">paris.json</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">?</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">access_token</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">YOUR_MAPBOX_ACCESS_TOKEN</span></span></code></pre></div><p><strong>Result prioritization in reverse geocoding</strong></p><p>For reverse geocodes, results at a given set of coordinates are sorted by order of <strong>spatial hierarchy</strong>. For example, a more granular feature such as an <code>address</code>, <code>poi</code>, or <code>postcode</code> will return first in the response before feature types like <code>region</code> or <code>country</code>. The full spatial hierarchy, ordered from the most granular to the largest, is: <em>point of interest (POI)</em>, <em>address</em>, <em>neighborhood</em>, <em>locality</em>, <em>postcode</em>, <em>place</em>, <em>district</em>, <em>region</em>, and <em>country</em>. (For more details about these geographic information types, see the Source data section.)</p><p>This reverse geocoding query example returns features closest to the query point (in the case of point features like <code>address</code> and <code>poi</code>) and features that contain the query point (in the case of polygon features like <code>place</code> or <code>region</code>), in order of hierarchy from the most granular (address or POI) to the largest feature (country):</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//api.mapbox.com/geocoding/v5/mapbox.places/-122.463%2C%2037.7648.json?access_token=YOUR_MAPBOX_ACCESS_TOKEN</span></span></code></pre></div><h3 id="access-mapbox-geocoding-services" tabindex="-1">Access Mapbox geocoding services <a href="#access-mapbox-geocoding-services" id="access-mapbox-geocoding-services"></a> <a class="header-anchor" href="#access-mapbox-geocoding-services" aria-label="Permalink to &quot;Access Mapbox geocoding services &lt;a href=&quot;#access-mapbox-geocoding-services&quot; id=&quot;access-mapbox-geocoding-services&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>You can access the Mapbox Geocoding API directly, through Mapbox Studio, or using one of several wrapper libraries to integrate it into applications across platforms.</p><h4 id="use-the-mapbox-geocoding-api" tabindex="-1">Use the Mapbox Geocoding API <a href="#use-the-mapbox-geocoding-api" id="use-the-mapbox-geocoding-api"></a> <a class="header-anchor" href="#use-the-mapbox-geocoding-api" aria-label="Permalink to &quot;Use the Mapbox Geocoding API &lt;a href=&quot;#use-the-mapbox-geocoding-api&quot; id=&quot;use-the-mapbox-geocoding-api&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>You can send requests to the Mapbox Geocoding API via many Mapbox mapping tools and plugins, but you can also make calls to the API directly using your preferred HTTP client. If you would like to make calls directly, read the <a href="https://docs.mapbox.com/api/search/geocoding/" target="_blank" rel="noreferrer">Geocoding API documentation</a>. If you want to use one of our other tools, see the Libraries and plugins section of this guide.</p><h4 id="test-the-geocoding-api" tabindex="-1">Test the Geocoding API <a href="#test-the-geocoding-api" id="test-the-geocoding-api"></a> <a class="header-anchor" href="#test-the-geocoding-api" aria-label="Permalink to &quot;Test the Geocoding API &lt;a href=&quot;#test-the-geocoding-api&quot; id=&quot;test-the-geocoding-api&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>If you would like to get a feel for how the Mapbox Geocoding API works without building a whole application, we also provide the <a href="https://docs.mapbox.com/playground/geocoding/" target="_blank" rel="noreferrer">Geocoding API Playground</a>. Besides providing a convenient user interface to test queries, the API playground allows you to test the API&#39;s URL and query parameters, such as <code>autocomplete</code> or <code>proximity</code>.</p><p><a href="https://docs.mapbox.com/search-playground/" target="_blank" rel="noreferrer">Visit the Search Playground</a></p><h4 id="geocoding-in-mapbox-studio" tabindex="-1">Geocoding in Mapbox Studio <a href="#geocoding-in-mapbox-studio" id="geocoding-in-mapbox-studio"></a> <a class="header-anchor" href="#geocoding-in-mapbox-studio" aria-label="Permalink to &quot;Geocoding in Mapbox Studio &lt;a href=&quot;#geocoding-in-mapbox-studio&quot; id=&quot;geocoding-in-mapbox-studio&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Mapbox Studio uses geocoding in the <a href="https://studio.mapbox.com/datasets/" target="_blank" rel="noreferrer">dataset editor</a>. When you search for places in the dataset editor&#39;s toolbar, you&#39;re using the Mapbox Geocoding API to find data to add to your custom dataset. Within the dataset editor, you can search for and add countries, regions, districts, postcodes, places, localities, neighborhoods, and addresses, but not POIs.</p><h4 id="libraries-and-plugins" tabindex="-1">Libraries and plugins <a href="#libraries-and-plugins" id="libraries-and-plugins"></a> <a class="header-anchor" href="#libraries-and-plugins" aria-label="Permalink to &quot;Libraries and plugins &lt;a href=&quot;#libraries-and-plugins&quot; id=&quot;libraries-and-plugins&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>If you would like to add a search tool to your application to find addresses, POIs, or features near your user&#39;s location, we have several wrapper libraries that allow you to integrate the Mapbox Geocoding API into your existing application seamlessly:</p><ul><li><a href="https://docs.mapbox.com/android/search/guides/" target="_blank" rel="noreferrer">Mapbox Search SDK for Android</a></li><li><a href="https://docs.mapbox.com/ios/search/guides/" target="_blank" rel="noreferrer">Mapbox Search SDK for iOS</a></li><li><a href="https://docs.mapbox.com/mapbox-gl-js/plugins/#mapbox-gl-geocoder" target="_blank" rel="noreferrer">Mapbox GL Geocoder</a> for Mapbox GL JS</li></ul><p>Here&#39;s an example of the <a href="https://docs.mapbox.com/mapbox-gl-js/plugins/#mapbox-gl-geocoder" target="_blank" rel="noreferrer">Mapbox GL Geocoder</a> in a map created with Mapbox GL JS with the query parameter <code>autocomplete=true</code>:</p><p>To build a similar web application using Mapbox GL JS, explore the <a href="https://docs.mapbox.com/mapbox-gl-js/example/point-from-geocoder-result/" target="_blank" rel="noreferrer">Set a point after geocoder result</a> example.</p><h4 id="pricing" tabindex="-1">Pricing <a href="#pricing" id="pricing"></a> <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing &lt;a href=&quot;#pricing&quot; id=&quot;pricing&quot;&gt;&lt;/a&gt;&quot;">​</a></h4><p>Use of the Geocoding API is billed by API requests. For more details, see the <a href="https://docs.mapbox.com/api/search/geocoding/#geocoding-api-pricing" target="_blank" rel="noreferrer">Geocoding API pricing page</a>.</p><h3 id="providing-geocoding-feedback" tabindex="-1">Providing geocoding feedback <a href="#providing-geocoding-feedback" id="providing-geocoding-feedback"></a> <a class="header-anchor" href="#providing-geocoding-feedback" aria-label="Permalink to &quot;Providing geocoding feedback &lt;a href=&quot;#providing-geocoding-feedback&quot; id=&quot;providing-geocoding-feedback&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>If you find an error or want to contribute map data, you can use our <a href="https://www.mapbox.com/contribute/" target="_blank" rel="noreferrer">Improve the map</a> tool.</p>',57)])])}const u=o(i,[["render",s]]);export{h as __pageData,u as default};
